CREATE OR REPLACE FUNCTION fpb_gos_payment_loan (as_conno char) RETURNS timestamp(0) AS $body$
DECLARE

  ldt_lastday timestamp(0);

BEGIN
  /*
    วันที่ชำระล่าสุด จากรายการเคลื่อไหว
  */
  select max(loan_payment_date)
  into STRICT ldt_lastday
  from
  (
    SELECT ld.loan_payment_date
      , sum( ld.payment_amount*lu.sign_status*(-1) ) as sum_p
    from sc_lon_m_loan_card_detail ld
     , sc_lon_m_ucf_loan_card_item lu
    where ld.loan_contract_no = as_conno  -- สม52001330
    and ld.item_type_code = lu.item_type_code
    group by ld.loan_payment_date
    order by ld.loan_payment_date
  ) alias3
  where sum_p > 0;

  return ldt_lastday;
exception when others then CALL spa_dberror('fpb_gos_payment_loan');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
